{
  "sentences": [
    {
      "text": "我們正在開會討論這個任務的進度。",
      "pinyin": "Wǒmen zhèngzài kāihuì tǎolùn zhège rènwu de jìndù.",
      "pinyin_numeric": "wo3men zheng4zai4 kai1hui4 tao3lun4 zhe4ge ren4wu0 de0 jin4du4.",
      "translation_en": "We are having a meeting to discuss the progress of this task.",
      "translation_ko": "저희는 지금 이 작업의 진행 상황을 논의하는 회의 중입니다."
    },
    {
      "text": "他正在檢查報告的細節。",
      "pinyin": "Tā zhèngzài jiǎnchá bàogào de xìjié.",
      "pinyin_numeric": "ta1 zheng4zai4 jian3cha2 bao4gao4 de0 xi4jie2.",
      "translation_en": "He is checking the details of the report.",
      "translation_ko": "그는 보고서의 세부 사항을 확인하고 있습니다."
    },
    {
      "text": "我現在在整理會議的資料。",
      "pinyin": "Wǒ xiànzài zài zhěnglǐ huìyì de zīliào.",
      "pinyin_numeric": "wo3 xian4zai4 zai4 zheng3li3 hui4yi4 de0 zi1liao4.",
      "translation_en": "I am organizing the meeting materials now.",
      "translation_ko": "저는 지금 회의 자료를 정리하고 있습니다."
    },
    {
      "text": "他們在討論提案，還沒有決定。",
      "pinyin": "Tāmen zài tǎolùn tí'àn, hái méiyǒu juédìng.",
      "pinyin_numeric": "ta1men zai4 tao3lun4 ti2'an4, hai2 mei2you3 jue2ding4.",
      "translation_en": "They are discussing the proposal and haven't decided yet.",
      "translation_ko": "그들은 제안을 논의 중이며 아직 결정하지 않았습니다."
    },
    {
      "text": "老闆在檢查我們完成的任務。",
      "pinyin": "Lǎobǎn zài jiǎnchá wǒmen wánchéng de rènwu.",
      "pinyin_numeric": "lao3ban3 zai4 jian3cha2 wo3men wan2cheng2 de0 ren4wu0.",
      "translation_en": "The boss is checking the tasks we have completed.",
      "translation_ko": "사장님이 우리가 완료한 작업을 확인하고 계십니다."
    },
    {
      "text": "她正在填寫會議的表格。",
      "pinyin": "Tā zhèngzài tiánxiě huìyì de biǎogé.",
      "pinyin_numeric": "ta1 zheng4zai4 tian2xie3 hui4yi4 de0 biao3ge2.",
      "translation_en": "She is filling out the meeting form.",
      "translation_ko": "그녀는 회의 양식을 작성하고 있습니다."
    },
    {
      "text": "我們在討論這個任務的目標。",
      "pinyin": "Wǒmen zài tǎolùn zhège rènwu de mùbiāo.",
      "pinyin_numeric": "wo3men zai4 tao3lun4 zhe4ge ren4wu0 de0 mu4biao1.",
      "translation_en": "We are discussing the goals of this task.",
      "translation_ko": "우리는 이 작업의 목표를 논의하고 있습니다."
    },
    {
      "text": "他正在修改報告，因為有錯誤。",
      "pinyin": "Tā zhèngzài xiūgǎi bàogào, yīnwèi yǒu cuòwù.",
      "pinyin_numeric": "ta1 zheng4zai4 xiu1gai3 bao4gao4, yin1wei4 you3 cuo4wu4.",
      "translation_en": "He is revising the report because there are mistakes.",
      "translation_ko": "그는 오류가 있어서 보고서를 수정하고 있습니다."
    },
    {
      "text": "我現在在確認會議的時間。",
      "pinyin": "Wǒ xiànzài zài quèrèn huìyì de shíjiān.",
      "pinyin_numeric": "wo3 xian4zai4 zai4 que4ren4 hui4yi4 de0 shi2jian1.",
      "translation_en": "I am confirming the meeting time now.",
      "translation_ko": "저는 지금 회의 시간을 확인하고 있습니다."
    },
    {
      "text": "他們在檢查檔案，然後更新狀態。",
      "pinyin": "Tāmen zài jiǎnchá dàng'àn, ránhòu gēngxīn zhuàngtài.",
      "pinyin_numeric": "ta1men zai4 jian3cha2 dang4'an4, ran2hou4 geng1xin1 zhuang4tai4.",
      "translation_en": "They are checking the files and then updating the status.",
      "translation_ko": "그들은 파일을 확인한 후 상태를 업데이트하고 있습니다."
    }
  ]
}
